#include<bits/stdc++.h>
using namespace std;
int dx[5]={0,-1,1,0,0};
int dy[5]={0,0,0,-1,1};
int n,m,x,y,k,s[210],t[210],d[210];
int dp[210][210][210];
char a[210][210];
int dfs(int now,int x,int y)
{
    if(now>k)
    {
        return 0;
    }
    if(dp[now][x][y]!=-1)
    {
        return dp[now][x][y];
    }
    int len=t[now]-s[now]+1,xx=x,yy=y;
    int ans=dfs(now+1,x,y);
    for(int i=1;i<=len;i++)
    {
        xx+=dx[d[now]];
        yy+=dy[d[now]];
        if(xx<1||xx>n||yy<1||yy>m||a[xx][yy]=='x')
        {
            break;
        }
        ans=max(ans,dfs(now+1,xx,yy)+i);
    }
    return dp[now][x][y]=ans;
}
int main()
{
    memset(dp,-1,sizeof(dp));
    scanf("%d%d%d%d%d",&n,&m,&x,&y,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
    }
    for(int i=1;i<=k;i++)
    {
        scanf("%d%d%d",&s[i],&t[i],&d[i]);
    }
    printf("%d",dfs(1,x,y));
    return 0;
}
